# -*- coding: utf-8 -*-

import threading
from abc import ABC, abstractmethod
from enum import Enum
import time
import queue

from PyQt6.QtCore import pyqtSignal, QObject

"""
后台任务中心
"""


class Status(Enum):
    PENDING = "Pending"
    RUNNING = "Running"
    COMPLETED = "Completed"


class TaskInterface(QObject):
    # 任务进度数值
    progress = 0

    # 信号量
    task_started = pyqtSignal(str)
    task_progress = pyqtSignal(int)
    task_finished = pyqtSignal()

    @abstractmethod
    def run(self):
        pass


class TaskWrapper:
    def __init__(self, task_obj):
        if not isinstance(task_obj, TaskInterface):
            raise ValueError("任务对象必须实现接口:TaskInterface")

        self.task_obj = task_obj
        self.status = Status.PENDING

    def execute(self):
        self.task_obj.task_started.emit("正在执行任务...")
        self.status = Status.RUNNING

        self.task_obj.run()
        self.status = Status.COMPLETED
        self.task_obj.task_finished.emit()


class SingleTaskCenter:
    def __init__(self):
        self.tasks = {}
        self.completed_tasks = []
        self.queue = queue.Queue()  # 任务队列
        self.current_task = None  # 当前执行的任务
        self.lock = threading.Lock()

    def add_task(self, task_name, task_obj):
        task_wrapper = TaskWrapper(task_obj)
        with self.lock:
            if self.queue.empty() and not self.tasks:
                self._execute_task(task_name, task_wrapper)
            else:
                self.queue.put((task_name, task_wrapper))

    def _execute_task(self, task_name, task_wrapper):
        with self.lock:
            self.current_task = (task_name, task_wrapper)
            self.tasks[task_name] = task_wrapper
            thread = threading.Thread(target=self._task_thread, args=(task_name,))
            thread.start()

    def _task_thread(self, task_name):
        task_wrapper = self.tasks[task_name]
        task_wrapper.execute()

        with self.lock:
            self.completed_tasks.append(task_name)
            del self.tasks[task_name]

            if not self.queue.empty():
                next_task_name, next_task_wrapper = self.queue.get()
                self._execute_task(next_task_name, next_task_wrapper)
            else:
                self.current_task = None

    def get_task_status(self, task_name):
        with self.lock:
            task_wrapper = self.tasks.get(task_name)
            if task_wrapper:
                return {
                    "name": task_name,
                    "status": task_wrapper.status.value,
                    "progress": task_wrapper.task_obj.progress
                }
            else:
                return None

    def get_current_task(self):
        with self.lock:
            if self.current_task:
                task_name, task_wrapper = self.current_task
                return {
                    "name": task_name,
                    "status": task_wrapper.status.value,
                    "progress": task_wrapper.task_obj.progress
                }
            else:
                return None

    def is_completed_task(self, task_name):
        with self.lock:
            return task_name in self.completed_tasks

    def list_tasks(self):
        with self.lock:
            return [{
                "name": name,
                "status": task.status.value,
                "progress": task.task_obj.progress
            } for name, task in self.tasks.items()]

    def list_completed_tasks(self):
        with self.lock:
            return self.completed_tasks

