class SimpleTestTask(TaskInterface):
    def __init__(self, name, duration):
        super().__init__()  # 调用父类的构造函数
        self.name = name
        self.duration = duration

    def run(self):
        for i in range(self.duration):
            self.progress = (i + 1) / self.duration * 100
            self.task_progress.emit(self.progress)
            time.sleep(1)


def test():
    task_center = SingleTaskCenter()

    # 创建任务对象
    task1 = SimpleTestTask("Task1", 5)
    task2 = SimpleTestTask("Task2", 10)

    # 添加任务到任务中心
    task_center.add_task("Task1", task1)
    task_center.add_task("Task2", task2)

    print(task_center.get_task_status("Task1"))
    print(task_center.get_task_status("Task2"))

    for i in range(20):
        time.sleep(1)
        # 查询任务状态
        print(task_center.get_task_status("Task1"))
        print(task_center.get_task_status("Task2"))


if __name__ == '__main__':
    test()
